function formatLarge(n) {
  if (!n) return '0'
  if (n >= 1e12) return (n/1e12).toFixed(1)+'T'
  if (n >= 1e8)  return (n/1e8).toFixed(1)+'B'
  if (n >= 1e4)  return (n/1e4).toFixed(1)+'K'
  return n.toLocaleString()
}

